function style(kind = "neutral") {
    if (!HAS_CARD_MOD) return {};

    const colors = {
        orange: "#f59e0b",
        green: "#22c55e",
        blue: "#38bdf8",
        purple: "#a855f7",
        cyan: "#06b6d4",
        neutral: "#64748b",
        red: "#ef4444"
    };

    return {
        card_mod: {
            style: `
                ha-card {
                    border-top: 4px solid ${colors[kind] || colors.neutral};
                    border-radius: 18px;
                    overflow: hidden;
                    box-shadow: 0 6px 18px rgba(0,0,0,0.12);
                }
            `
        }
    };
}

function titleCard(title, subtitle, kind = "neutral") {
    return {
        type: "markdown",
        content: `# ${title}\n## ${subtitle}`,
        ...style(kind)
    };
}

function infoCard(content, kind = "neutral") {
    return {
        type: "markdown",
        content,
        ...style(kind)
    };
}

function tile(entityId, name, icon, kind) {
    return {
        type: "tile",
        entity: entityId,
        name,
        icon,
        vertical: false,
        hide_state: false,
        features_position: "bottom",
        ...style(kind)
    };
}

function grid(columns, cards) {
    return {
        type: "grid",
        columns,
        square: false,
        cards: cards.filter(Boolean)
    };
}

function stack(cards) {
    return {
        type: "vertical-stack",
        cards: cards.filter(Boolean)
    };
}

function entitiesCard(title, entities, kind) {
    return {
        type: "entities",
        title,
        show_header_toggle: false,
        entities,
        ...style(kind)
    };
}

function donutCard(title, series, kind = "neutral", height = 430) {
    if (!HAS_APEXCHARTS) {
        return entitiesCard(title, series.map(s => ({
            entity: s.entity,
            name: s.name
        })), kind);
    }

    return {
        type: "custom:apexcharts-card",
        chart_type: "donut",
        header: {
            show: true,
            title: title,
            show_states: true,
            colorize_states: true,
            standard_format: true,
            floating: false
        },
        all_series_config: {
            float_precision: 2,
            show: {
                in_header: true,
                legend_value: true
            }
        },
        series: series,
        apex_config: {
            chart: {
                height: height
            },
            legend: {
                show: true,
                position: "bottom",
                formatter: function (seriesName, opts) {
                    const raw = opts?.w?.globals?.series?.[opts.seriesIndex];
                    const n = Number(raw);
                    if (!Number.isFinite(n)) return seriesName;
                    const cents = Math.round(n * 100);
                    const clean = cents / 100;
                    return `${seriesName}: ${clean.toLocaleString("fr-FR", {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2
                    })}`;
                }
            },
            dataLabels: {
                enabled: true,
                formatter: function (_val, opts) {
                    const raw = opts?.w?.globals?.series?.[opts.seriesIndex];
                    const n = Number(raw);
                    if (!Number.isFinite(n)) return "";
                    const cents = Math.round(n * 100);
                    const clean = cents / 100;
                    return clean.toLocaleString("fr-FR", {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2
                    });
                },
                style: {
                    fontSize: "13px",
                    fontWeight: "bold"
                },
                dropShadow: {
                    enabled: false
                }
            },
            plotOptions: {
                pie: {
                    donut: {
                        size: "58%",
                        labels: {
                            show: true,
                            name: {
                                show: true,
                                offsetY: 18
                            },
                            value: {
                                show: true,
                                offsetY: -18,
                                formatter: function (val) {
                                    const n = Number(val);
                                    if (!Number.isFinite(n)) return "";
                                    const cents = Math.round(n * 100);
                                    const clean = cents / 100;
                                    return clean.toLocaleString("fr-FR", {
                                        minimumFractionDigits: 2,
                                        maximumFractionDigits: 2
                                    });
                                }
                            },
                            total: {
                                show: true,
                                showAlways: true,
                                label: "Total",
                                formatter: function (w) {
                                    const totals = Array.isArray(w?.globals?.seriesTotals)
                                        ? w.globals.seriesTotals
                                        : [];
                                    const totalCents = totals.reduce((acc, value) => {
                                        const n = Number(value);
                                        if (!Number.isFinite(n)) return acc;
                                        return acc + Math.round(n * 100);
                                    }, 0);
                                    const clean = totalCents / 100;
                                    return clean.toLocaleString("fr-FR", {
                                        minimumFractionDigits: 2,
                                        maximumFractionDigits: 2
                                    });
                                }
                            }
                        }
                    }
                }
            },
            stroke: {
                width: 2
            },
            tooltip: {
                y: {
                    formatter: function (value) {
                        const n = Number(value);
                        if (!Number.isFinite(n)) return value;
                        const cents = Math.round(n * 100);
                        const clean = cents / 100;
                        return clean.toLocaleString("fr-FR", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2
                        });
                    }
                }
            }
        },
        ...style(kind)
    };
}

function historyChart(title, attributeName, kind = "neutral", height = 320, graphSpan = "365d") {
    if (!HAS_APEXCHARTS) {
        return entitiesCard(title, [
            { entity: E.historyArchive, name: E.historyArchive }
        ], kind);
    }

    const points =
        attributeName === "daily" ? 30 :
            attributeName === "monthly" ? 12 :
                10;

    const forcedGraphSpan =
        attributeName === "daily" ? "30d" :
            attributeName === "monthly" ? "365d" :
                "3650d";

    const columnWidth =
        attributeName === "daily" ? "38%" :
            attributeName === "monthly" ? "48%" :
                "56%";

    const xFormat =
        attributeName === "daily" ? "dd MMM" :
            attributeName === "monthly" ? "MMM yy" :
                "yyyy";

    const tooltipFormat =
        attributeName === "daily" ? "dd MMM yyyy" :
            attributeName === "monthly" ? "MMM yyyy" :
                "yyyy";

    return {
        type: "custom:apexcharts-card",
        header: {
            show: true,
            title: title,
            show_states: true,
            colorize_states: true,
            floating: false
        },
        all_series_config: {
            float_precision: 2,
            show: {
                in_header: true,
                legend_value: true
            }
        },
        graph_span: forcedGraphSpan,
        span: {
            end: "day"
        },
        series: [
            {
                entity: E.historyArchive,
                name: title,
                type: "column",
                float_precision: 2,
                data_generator: `
const raw = entity?.attributes?.["${attributeName}"];
const arr = Array.isArray(raw) ? raw : [];
const out = [];
const now = new Date();

function pad(v) {
    return String(v).padStart(2, "0");
}

function dayKey(d) {
    return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-" + pad(d.getDate());
}

function monthKey(d) {
    return d.getFullYear() + "-" + pad(d.getMonth() + 1);
}

function yearKey(d) {
    return String(d.getFullYear());
}

function valueFor(item) {
    const v = Number(item?.savings_vs_no_solar ?? item?.real_total_with_subscription ?? 0);
    return Number.isFinite(v) ? Number(v.toFixed(2)) : 0;
}

const map = {};
for (const item of arr) {
    if (item && item.key) {
        map[item.key] = valueFor(item);
    }
}

if ("${attributeName}" === "daily") {
    for (let i = ${points - 1}; i >= 0; i--) {
        const d = new Date(now);
        d.setHours(0, 0, 0, 0);
        d.setDate(d.getDate() - i);
        const key = dayKey(d);
        out.push([d.getTime(), map[key] ?? 0]);
    }
} else if ("${attributeName}" === "monthly") {
    for (let i = ${points - 1}; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1, 0, 0, 0, 0);
        const key = monthKey(d);
        out.push([d.getTime(), map[key] ?? 0]);
    }
} else {
    for (let i = ${points - 1}; i >= 0; i--) {
        const d = new Date(now.getFullYear() - i, 0, 1, 0, 0, 0, 0);
        const key = yearKey(d);
        out.push([d.getTime(), map[key] ?? 0]);
    }
}

return out;
                `
            }
        ],
        apex_config: {
            chart: {
                height: height
            },
            plotOptions: {
                bar: {
                    borderRadius: 6,
                    columnWidth: columnWidth
                }
            },
            dataLabels: {
                enabled: false
            },
            stroke: {
                width: 1
            },
            xaxis: {
                type: "datetime",
                labels: {
                    datetimeUTC: false,
                    format: xFormat
                }
            },
            yaxis: {
                decimalsInFloat: 2,
                labels: {
                    formatter: function (value) {
                        const n = Number(value);
                        if (!Number.isFinite(n)) return value;
                        return n.toLocaleString("fr-FR", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2
                        });
                    }
                }
            },
            tooltip: {
                x: {
                    format: tooltipFormat
                },
                y: {
                    formatter: function (value) {
                        const n = Number(value);
                        if (!Number.isFinite(n)) return value;
                        return n.toLocaleString("fr-FR", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2
                        });
                    }
                }
            }
        },
        ...style(kind)
    };
}

