msg.filename = "/config/dashboards/smart_energy_finance.json";
msg.payload = JSON.stringify(dashboard, null, 2);
return msg;

const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

// 2ème digit : premium actif ou non
const premium = global.get('premium') || {};
const premiumDigit = (premium.status === 'active') ? '1' : '0';

msg.filename = configPath;
msg.payload = { "bip": String(bip) + premiumDigit };  // ex: "11", "10", "21"...
msg.headers = { "Content-Type": "application/json" };
node.status({fill: statusColor, shape: "dot", text: msg.environment});
return msg;
